<template>
  <div class='chat-avatar-container' ref='avatarRef'>
    <el-avatar
      v-if="role !== 'user'"
      :src="avatarSrc"
      :icon="avatarIcon"
      :style="avatarStyle"
    />
    <div v-else class="user-avatar">{{ shortName }}</div>
    <div v-if="isSticky" class="sticky-time">{{ stickyTime }}</div>
  </div>
</template>

<script lang="ts">
