.280691,33.959566210937496Q0.141582,34.3135662109375,0.0707912,34.6872662109375Q0,35.0609662109375,0,35.4413662109375Q0,35.6403662109375,0.0195095,35.8384662109375Q0.0390189,36.0365662109375,0.07785,36.2317662109375Q0.116681,36.4269662109375,0.17446,36.6174662109375Q0.232238,36.8079662109375,0.308408,36.9917662109375Q0.384578,37.1756662109375,0.478406,37.3512662109375Q0.572233,37.5267662109375,0.682815,37.6922662109375Q0.793396,37.8577662109375,0.919667,38.0116662109375Q1.04594,38.1654662109375,1.18668,38.3062662109375Q1.32742,38.4469662109375,1.48129,38.5732662109375Q1.63515,38.6995662109375,1.80064,38.8100662109375Q1.96614,38.9206662109375,2.14168,39.0144662109375Q2.31722,39.1083662109375,2.50111,39.1844662109375Q2.685,39.2606662109375,2.87547,39.3184662109375Q3.06594,39.3762662109375,3.26116,39.4150662109375Q3.45637,39.4538662109375,3.65446,39.4733662109375Q3.85254,39.4929662109375,4.05158,39.4929662109375L14.3156,39.4929662109375Q14.5146,39.4929662109375,14.7127,39.4733662109375Q14.9108,39.4538662109375,15.106,39.4150662109375Q15.3012,39.3762662109375,15.4917,39.3184662109375Q15.6822,39.2606662109375,15.8661,39.1844662109375Q16.05,39.1083662109375,16.2255,39.0144662109375Q16.401,38.9206662109375,16.5665,38.8100662109375Q16.732,38.6995662109375,16.8859,38.5732662109375Q17.0397,38.4469662109375,17.1805,38.3062662109375Q17.3212,38.1654662109375,17.4475,38.0116662109375Q17.5738,37.8577662109375,17.6844,37.6922662109375Q17.7949,37.5267662109375,17.8888,37.3512662109375Q17.9826,37.1756662109375,18.0588,36.9917662109375Q18.1349,36.8079662109375,18.1927,36.6174662109375Q18.2505,36.4269662109375,18.2893,36.2317662109375Q18.3282,36.0365662109375,18.3477,35.8384662109375Q18.3672,35.6403662109375,18.3672,35.4413662109375Q18.3672,35.2422662109375,18.3477,35.0441662109375Q18.3282,34.8461662109375,18.2893,34.6508662109375Q18.2505,34.4556662109375,18.1927,34.2652662109375Q18.1349,34.0747662109375,18.0588,33.8908662109375Q17.9826,33.7069662109375,17.8888,33.531466210937495Q17.7949,33.3558662109375,17.6844,33.1903662109375Q17.5738,33.0248662109375,17.4475,32.8710662109375Q17.3212,32.7171662109375,17.1805,32.5764662109375Q17.0397,32.4356662109375,16.8859,32.3094662109375Q16.732,32.1831662109375,16.5665,32.072566210937495Q16.401,31.9619662109375,16.2255,31.8681662109375Q16.05,31.7743662109375,15.8661,31.6981662109375Q15.6822,31.6219662109375,15.4917,31.5641662109375Q15.3012,31.5064662109375,15.106,31.4675662109375Q14.9108,31.4287662109375,14.7127,31.4092662109375Q14.5146,31.3897662109375,14.3156,31.3897662109375L11.1873,31.3897662109375Z" fill-rule="evenodd" fill="#FFFFFF" fill-opacity="1"/></g></g></svg>');

// 默认配置
export const defaultConfig = {
  user: {
    src: defaultUserAvatar,
    backgroundColor: 'transparent',
    size: [20, 20],
    icon: undefined,
  },
  ai: {
    src: defaultAiAvatar,
    backgroundColor: 'var(--hatech-primary-color)',
    size: [20, 20],
    icon: undefined,
  },
};

export default defineComponent({
  name: 'AiAvatar',
  props: {
    role: {
      type: String,
      default: 'user',
    },
    name: {
      type: String,
      default: ''
    },
    avatars: {
      type: [Boolean, String, Object] as PropType<boolean | string | MessageAvatar>,
      default: true,
    },
    time: {
      type: String,
      default: ''
    },
    scrollContainer: {
      type: [Object, HTMLElement] as PropType<HTMLElement | null>,
      default: null,
    },
  },
  setup(props) {
    const isSticky = ref(false);
    const avatarRef = ref<HTMLElement | null>(null);
    const stickyTime = computed(() => props.time);

    let observer: IntersectionObserver;
    onMounted(() => {
      // 必须确保两个元素都存在
      if (!avatarRef.value || !props.scrollContainer) {
        return;
      }

      const options = {
        // root: 明确指定滚动容器，而不是默认的视口
        root: props.scrollContainer,
        // rootMargin: 这是关键！我们在容器顶部创建了一个1px高的“触发线”。
        // 当元素顶部进入这个-1px的区域时，交叉状态就会改变。
        rootMargin: '-1px 0px 0px 0px',
        // threshold: 我们关心的是元素是否“完全可见”。
        // 当它向上滚动并触及触发线时，它就不再是100%可见了。
        threshold: [1.0],
      };

      observer = new IntersectionObserver(([entry]) => {
        // 当元素的可见比例小于1时，意味着它的顶部已经触碰或越过了我们的“触发线”。
        // 这就是它吸顶的精确时刻。
        isSticky.value = entry.intersectionRatio < 1;
      }, options);

      observer.observe(avatarRef.value);
    });

    onBeforeUnmount(() => {
      // 清理 observer
      if (observer) {
        observer.disconnect();
      }
    });

    const shortName = computed(() => {
      if (typeof props.name !== 'string') return '';
      return props.name.length >= 2 ? props.name.slice(-2).toUpperCase() : props.name.toUpperCase();
    });
    const getAvatarConfig = (role: string, name: string, avatars: any) => {
      if (avatars === true) {
        return defaultConfig[role === 'user' ? 'user' : 'ai'];
      }

      if (typeof avatars === 'string') {
        try {
          avatars = JSON.parse(avatars);
        } catch (error) {
          return defaultConfig[role === 'user' ? 'user' : 'ai'];
        }
      }

      // 如果是对象类型，合并默认配置和用户配置
      if (typeof avatars === 'object') {
        // 获取当前角色的配置
        const roleConfig = avatars[name] || {};
        // 获取默认角色的配置
        const defaultRoleConfig = defaultConfig[role === 'user' ? 'user' : 'ai'];

        return {
          src: roleConfig.src || defaultRoleConfig.src,
          backgroundColor: roleConfig.backgroundColor ?? defaultRoleConfig.backgroundColor,
          size: roleConfig.size || defaultRoleConfig.size,
          icon: roleConfig.icon || defaultRoleConfig.icon,
        };
      }

      return defaultConfig[role === 'user' ? 'user' : 'ai'];
    };

    const avatarConfig = computed(() => getAvatarConfig(props.role, props.name, props.avatars));

    const avatarSrc = computed(() => {
      const { src } = avatarConfig.value;
      if (!src) return null;
      if (src.startsWith('data:') || src.includes('http')) {
        return src;
      }
      return src;
    });

    const avatarIcon = computed(() => avatarSrc.value ? null : avatarConfig.value.icon);

    const avatarStyle = computed(() => {
      const style: any = {};

      if (avatarConfig.value.backgroundColor) {
        style.backgroundColor = avatarConfig.value.backgroundColor;
      }

      if (avatarConfig.value.size) {
        style['--avatar-img-size'] = Array.isArray(avatarConfig.value.size)
          ? `${avatarConfig.value.size[0]}px`
          : `${avatarConfig.value.size}px`;
      }

      if (props.role === 'user') {
        style.border = '1px solid var(--hatech-primary-color)';
      }

      return style;
    });

    return {
      shortName,
      avatarSrc,
      avatarIcon,
      avatarStyle,
      isSticky,
      avatarRef,
      stickyTime,
    };
  },
});
</script>

<style scoped lang="scss">
.chat-avatar-container {
  position: relative;
  width: 32px;
  height: 32px;
}
.el-avatar {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: transparent;

  ::v-deep img {
    width: var(--avatar-img-size, 32px) !important;
    height: var(--avatar-img-size, 32px) !important;
    object-fit: contain;
  }
}

.user-avatar {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  font-size: 12px;
  line-height: 18px;
  color: var(--hatech-primary-color);
  font-weight: 600;
  background-color: transparent;
  border: 1px solid var(--hatech-primary-color);
  border-radius: 50%;
}

.sticky-time {
  font-size: 12px;
  color: var(--one-base-font-color-secondary-info);
  margin-top: 4px;
  //white-space: nowrap;
}
</style>
